import torch
import requests
from torch.utils.model_zoo import load_url as load_url_torchvision

def download_and_load(model_name, url):
    print(f'Downloading {model_name}...')
    response = requests.get(url)
    if response.status_code == 200:
        torch.save(torch.load(response), f'{model_name}.pt')
        print(f'Successfully downloaded and saved {model_name}!')
    else:
        print(f'Failed to download {model_name}. Check the URL.')

# Example usage
